import React from "react";
import { useNavigate } from "react-router-dom";

const Layout = ({ children, pageTitle = "NexaLearn LMS" }) => {
  const navigate = useNavigate();
  const userRole = localStorage.getItem("role");

  const handleLogout = () => {
    localStorage.removeItem("role");
    navigate("/");
  };

  const formattedRole =
    userRole?.charAt(0).toUpperCase() + userRole?.slice(1);

  return (
    <div
      style={{
        minHeight: "100vh",
        background: "#f4f6f9",
        display: "flex",
        flexDirection: "column",
        fontFamily: "'Inter', 'Segoe UI', sans-serif",
      }}
    >
      {/* HEADER */}
      <header
        style={{
          background: "linear-gradient(90deg, #8b0000, #5c0000)",
          padding: "14px 40px",
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          boxShadow: "0 4px 20px rgba(0,0,0,0.08)",
          position: "sticky",
          top: 0,
          zIndex: 1000,
        }}
      >
        {/* Left Section */}
        <div style={{ display: "flex", alignItems: "center", gap: "18px" }}>
          <img
            src="https://upload.wikimedia.org/wikipedia/en/thumb/7/7a/Koneru_Lakshmaiah_University_logo.png/220px-Koneru_Lakshmaiah_University_logo.png"
            alt="Nexa Logo"
            style={{
              height: "42px",
              borderRadius: "6px",
              background: "#fff",
              padding: "4px",
            }}
          />

          <h1
            style={{
              color: "#ffffff",
              fontSize: "1.25rem",
              fontWeight: "600",
              margin: 0,
              letterSpacing: "0.5px",
            }}
          >
            {pageTitle}
          </h1>
        </div>

        {/* Right Section */}
        {userRole && (
          <div style={{ display: "flex", alignItems: "center", gap: "18px" }}>
            {/* Role Badge */}
            <div
              style={{
                background: "rgba(255,255,255,0.15)",
                color: "#fff",
                padding: "6px 14px",
                borderRadius: "20px",
                fontSize: "0.85rem",
                fontWeight: "500",
              }}
            >
              {formattedRole}
            </div>

            {/* Logout Button */}
            <button
              onClick={handleLogout}
              style={{
                background: "#ffffff",
                color: "#8b0000",
                border: "none",
                padding: "8px 18px",
                borderRadius: "25px",
                fontWeight: "600",
                cursor: "pointer",
                transition: "all 0.25s ease",
                boxShadow: "0 2px 8px rgba(0,0,0,0.1)",
              }}
              onMouseEnter={(e) =>
                (e.currentTarget.style.background = "#f2f2f2")
              }
              onMouseLeave={(e) =>
                (e.currentTarget.style.background = "#ffffff")
              }
            >
              Logout
            </button>
          </div>
        )}
      </header>

      {/* MAIN CONTENT */}
      <main
        style={{
          flex: 1,
          maxWidth: "1200px",
          width: "95%",
          margin: "40px auto",
          background: "#ffffff",
          padding: "40px",
          borderRadius: "12px",
          boxShadow: "0 15px 40px rgba(0,0,0,0.06)",
        }}
      >
        {children}
      </main>
    </div>
  );
};

export default Layout;
